import { createSlice } from '@reduxjs/toolkit';

const counterSlice = createSlice({
  name: 'counter',
  initialState: { value: 0 },
  reducers: {
    increment: (state) => {
      state.value += 1;
    },
    decrement: (state) => {
      state.value -= 1;
    },
    incrementByAmount: (state, action) => {
      state.value += action.payload;
    }
  }
});

export const { increment, decrement, incrementByAmount } = counterSlice.actions;
export default counterSlice.reducer;

import { createSlice, createSelector } from '@reduxjs/toolkit';

const cartSlice = createSlice({
  name: 'cart',
  initialState: { items: [] },
  reducers: {
    addItem: (state, action) => {
      const existingItem = state.items.find(item => item.id === action.payload.id);
      if (existingItem) {
        existingItem.quantity += 1;
      } else {
        state.items.push({ ...action.payload, quantity: 1 });
      }
    },
    removeItem: (state, action) => {
      state.items = state.items.filter(item => item.id !== action.payload);
    },
    updateQuantity: (state, action) => {
      const { id, delta } = action.payload;
      const item = state.items.find(item => item.id === id);
      if (item) {
        const newQuantity = item.quantity + delta;
        if (newQuantity <= 0) {
          state.items = state.items.filter(i => i.id !== id);
        } else {
          item.quantity = newQuantity;
        }
      }
    },
    clearCart: (state) => {
      state.items = [];
    }
  }
});

export const { addItem, removeItem, updateQuantity, clearCart } = cartSlice.actions;
export default cartSlice.reducer;

// Sélecteur mémorisé pour le total
export const selectCartTotal = createSelector(
  (state) => state.cart.items,
  (items) => items.reduce((total, item) => total + (item.prix * item.quantity), 0)
);

// Sélecteur pour le nombre total d'articles
export const selectCartItemCount = createSelector(
  (state) => state.cart.items,
  (items) => items.reduce((count, item) => count + item.quantity, 0)
);

L'erreur est le 'return state' dans le reducer. Redux Toolkit utilise Immer qui permet d'écrire du code "mutatif". Lorsqu'on retourne explicitement une valeur, cela court-circuite le mécanisme d'Immer et peut causer des problèmes. La correction consiste à supprimer la ligne 'return state' et laisser Immer gérer la mutation automatiquement. Code corrigé :

const userSlice = createSlice({
  name: 'user',
  initialState: { data: null },
  reducers: {
    setUser: (state, action) => {
      state.data = action.payload;
    }
  }
});
